#include <stdio.h>

void print_bits(unsigned int n) {
    for (int i = 7; i >= 0; i--) {
        printf("%d", (n >> i) & 1);
    }
    printf("\n");
}

int main(void) {
    unsigned int a = 0b10101010; /* 170 */
    unsigned int b = 0b11001100; /* 204 */

    printf("a     = "); print_bits(a);     /* 10101010 */
    printf("b     = "); print_bits(b);     /* 11001100 */
    printf("a & b = "); print_bits(a & b); /* 10001000 (AND) */
    printf("a | b = "); print_bits(a | b); /* 11101110 (OR) */
    printf("a ^ b = "); print_bits(a ^ b); /* 01100110 (XOR) */
    printf("~a    = "); print_bits(~a);    /* 01010101 (NOT, low 8 bits) */

    /* Shift operators */
    unsigned int x = 1;
    printf("1 << 3 = %u\n", x << 3);  /* 8 (multiply by 2^3) */
    printf("8 >> 2 = %u\n", 8u >> 2);  /* 2 (divide by 2^2) */

    /* Practical: extract a bit */
    unsigned int val = 0xA5; /* 10100101 */
    int bit3 = (val >> 3) & 1;
    printf("bit 3 of 0xA5 = %d\n", bit3); /* 0 */

    /* Practical: set a bit */
    val = val | (1 << 3); /* set bit 3 */
    printf("after set bit 3: 0x%X\n", val); /* 0xAD */

    return 0;
}

