#include <stdio.h>

int main(void) {
    int x = 10;

    x += 5;   printf("x += 5:  %d\n", x);  /* 15 */
    x -= 3;   printf("x -= 3:  %d\n", x);  /* 12 */
    x *= 2;   printf("x *= 2:  %d\n", x);  /* 24 */
    x /= 4;   printf("x /= 4:  %d\n", x);  /* 6  */
    x %= 4;   printf("x %%= 4:  %d\n", x); /* 2  */

    /* Bitwise compound */
    unsigned int flags = 0x00;
    flags |= 0x01;  /* set bit 0 */
    flags |= 0x04;  /* set bit 2 */
    printf("flags = 0x%02X\n", flags); /* 0x05 */
    flags &= ~0x01; /* clear bit 0 */
    printf("flags = 0x%02X\n", flags); /* 0x04 */

    /* Assignment chaining */
    int a, b, c;
    a = b = c = 42;
    printf("a=%d b=%d c=%d\n", a, b, c); /* 42 42 42 */

    /* Assignment as expression value */
    int n;
    if ((n = 5) > 0) {
        printf("n = %d\n", n); /* 5 */
    }

    return 0;
}

