#include <stdio.h>

int main(void) {
    /* Comma operator: left evaluated, right returned */
    int x = (1, 2, 3);
    printf("x = %d\n", x); /* 3 (last value) */

    /* Side effects in left operand */
    int a = 0;
    int b = (a = 5, a + 10);
    printf("a=%d b=%d\n", a, b); /* a=5 b=15 */

    /* Common use: multiple updates in for-loop */
    for (int i = 0, j = 5; i < j; i++, j--) {
        printf("i=%d j=%d\n", i, j);
    }
    /* Output: i=0 j=5, i=1 j=4, i=2 j=3 */

    /* NOT the comma operator (function argument separator) */
    printf("%d %d\n", 10, 20); /* comma here is a separator */

    /* Lowest precedence */
    int y;
    y = 1, 2;  /* y = 1 (assignment binds tighter than comma) */
    printf("y = %d\n", y); /* 1, not 2 */

    y = (1, 2); /* now y = 2 (parentheses force comma operator) */
    printf("y = %d\n", y); /* 2 */

    return 0;
}

