int main(void) {
    /* Precedence: * before + */
    int a = 2 + 3 * 4;   /* 2 + 12 = 14, not 20 */
    printf("%d\n", a);    /* 14 */

    /* CLASSIC BUG: bitwise & has lower precedence than == */
    int x = 5;  /* binary: 0101 */
    /* if (x & 1 == 0)   // WRONG: parsed as x & (1 == 0) = x & 0 = 0 */
    if ((x & 1) == 0) {  /* CORRECT: test if x is even */
        printf("even\n");
    } else {
        printf("odd\n"); /* This prints */
    }

    /* Associativity: right-to-left for assignment */
    int p, q, r;
    p = q = r = 10;  /* r=10, then q=10, then p=10 */
    printf("p=%d q=%d r=%d\n", p, q, r);

    /* Associativity: left-to-right for arithmetic */
    int result = 10 - 5 - 2;  /* (10-5)-2 = 3, not 10-(5-2)=7 */
    printf("%d\n", result);    /* 3 */

    /* When in doubt, use parentheses! */
    int y = ((2 + 3) * 4);  /* clearly 20 */
    printf("%d\n", y);

    return 0;
}

