#include <stdio.h>

int main(void) {
    /* int + double -> double */
    int i = 5;
    double d = 2.5;
    printf("5 + 2.5 = %f\n", i + d); /* 7.500000 (double) */

    /* int + float -> float */
    float f = 3.0f;
    printf("5 + 3.0f = %f\n", i + f); /* 8.000000 */

    /* int + unsigned int -> unsigned int */
    int neg = -1;
    unsigned int pos = 1;
    printf("-1 + 1u = %u\n", neg + pos); /* 0 (correct by luck) */
    printf("-1 > 1u? %d\n", neg > pos);  /* 1 (true! -1 -> UINT_MAX) */

    /* char arithmetic -> promoted to int */
    char a = 100, b = 50;
    printf("sizeof(a+b) = %zu\n", sizeof(a + b)); /* sizeof(int) */

    /* Integer division vs float division */
    printf("5/2   = %d\n", 5 / 2);          /* 2 (int division) */
    printf("5/2.0 = %f\n", 5 / 2.0);        /* 2.500000 (promoted) */
    printf("(double)5/2 = %f\n", (double)5 / 2); /* 2.500000 */

    return 0;
}

