    double pi = 3.14159;
    int truncated = (int)pi;
    printf("(int)3.14159 = %d\n", truncated); /* 3 */
    printf("(int)-3.7 = %d\n", (int)-3.7);   /* -3 (toward zero) */

    /* Pointer casting */
    void *ptr = malloc(sizeof(int));
    if (ptr) {
        int *ip = (int *)ptr; /* explicit cast (optional in C, required in C++) */
        *ip = 42;
        printf("*ip = %d\n", *ip);
        free(ptr);
    }

    /* Suppress unused warning */
    int unused = 0;
    (void)unused; /* tell compiler: intentionally unused */

    /* Dangerous: narrow cast with data loss */
    int big = 300;
    char small = (char)big; /* truncated! */
    printf("(char)300 = %d\n", small); /* platform-dependent, likely 44 */

