    } else {
        printf("Division by zero avoided\n");
    }

    /* SAFE: check before signed arithmetic */
    int x = INT_MAX;
    int y = 1;
    if (y > 0 && x > INT_MAX - y) {
        printf("Overflow would occur\n");
    } else if (y > 0) {
        printf("%d\n", x + y);
    }

    /* SAFE: check shift amount */
    int shift = 31;
