#include <stdio.h>

struct Padded {
    char c;   /* 1 byte + 3 padding */
    int x;    /* 4 bytes */
};             /* total: likely 8, not 5 */

int main(void) {
    /* Type */
    printf("sizeof(int)   = %zu\n", sizeof(int));    /* 4 */
    printf("sizeof(char)  = %zu\n", sizeof(char));   /* 1 (always) */

    /* Array */
    int arr[10];
    printf("sizeof(arr)   = %zu\n", sizeof(arr));    /* 40 */
    printf("elements      = %zu\n", sizeof(arr)/sizeof(arr[0])); /* 10 */

    /* Pointer */
    int *p = arr;
    printf("sizeof(p)     = %zu\n", sizeof(p));      /* 8 on 64-bit */

    /* String literal (includes '\0') */
    printf("sizeof(\"hello\") = %zu\n", sizeof("hello")); /* 6 */

    /* Struct with padding */
    printf("sizeof(Padded)= %zu\n", sizeof(struct Padded)); /* likely 8 */

    /* Expression not evaluated */
    int x = 5;
    printf("sizeof(x++)   = %zu\n", sizeof(x++)); /* sizeof(int) */
    printf("x = %d\n", x); /* still 5! */

    /* Result type of expression */
    char a = 1;
    short b = 2;
    printf("sizeof(a+b)   = %zu\n", sizeof(a + b)); /* sizeof(int) */

    return 0;
}

